                if (ngx_str6cmp(m, 'D', 'E', 'L', 'E', 'T', 'E')) {
                    r->method = NGX_HTTP_DELETE;
                    break;
                }

                if (ngx_str6cmp(m, 'U', 'N', 'L', 'O', 'C', 'K')) {
                    r->method = NGX_HTTP_UNLOCK;
                    break;
                }

