                if (ngx_str7_cmp(m, 'O', 'P', 'T', 'I', 'O', 'N', 'S', ' '))
                {
                    r->method = NGX_HTTP_OPTIONS;
                }

                if (ngx_str7_cmp(m, 'C', 'O', 'N', 'N', 'E', 'C', 'T', ' '))
                {
                    r->method = NGX_HTTP_CONNECT;
                    state = sw_spaces_before_host;
                }

