            case CR:
                state = sw_trailer_header_almost_done;
                break;
            case LF:
                goto invalid;
            }
            break;

        case sw_trailer_header_almost_done:
            if (ch == LF) {
                state = sw_trailer;
                break;
            }
            goto invalid;

        }
    }

